1548: test "expect State.add auto-fill missing horn at buffer_effective boundary" {
1549:     // Arrange: place the incomplete pair at indices 14..15 so a trigger pushes
1550:     // total length to 17, exceeding buffer_effective. The implementation must
1551:     // both mutate the existing vowel and follow the overflow convention from
1552:     // the literal `else` arm (set literal_index to buffer_effective.len).
1553:     const Case = struct {
1554:         first_base: u8,
1555:         first_diacritic: Diacritic,
1556:         second_base: u8,
1557:         second_diacritic: Diacritic,
1558:         receiving_offset: u8,
1559:     };
1560:     const cases = [_]Case{
1561:         // uơ pattern: first vowel at index 14 receives horn.
1562:         .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
1563:         // ưo pattern: second vowel at index 15 receives horn.
1564:         .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
1565:     };
1566: 
1567:     for (cases) |c| {
1568:         var state: State = undefined;
1569:         state.init();
1570:         state.mode = .telex;
1571: 
1572:         // Fill indices 0..13 with literal 'b'.
1573:         for (0..14) |i| {
1574:             state.buffer_effective[i] = Span.init('b');
1575:         }
1576:         state.buffer_effective[14] = Span.init_diacritic_tone(c.first_base, c.first_diacritic, .level);
1577:         state.buffer_effective[15] = Span.init_diacritic_tone(c.second_base, c.second_diacritic, .level);
1578:         state.buffer_length = 16;
1579: 
1580:         // Act
1581:         state.add('n');
1582: 
1583:         // Assert
1584:         const receiving_index = 14 + c.receiving_offset;
1585:         try expectEqual(17, state.buffer_length);
1586:         try expectEqual(receiving_index, state.buffer_modification_index);
1587:         // Trigger append exceeds buffer_effective, switch to literal from the
1588:         // first out-of-range position (buffer_effective.len = 16).
1589:         try expectEqual(16, state.literal_index);
1590:         try expectEqual(.telex, state.mode);
1591: 
1592:         // Prefix spans 0..13 unchanged.
1593:         for (0..14) |i| {
1594:             const sp = state.buffer_effective[i];
1595:             try expectEqual(@as(u8, 'b'), sp.base);
1596:             try expectEqual(.empty, sp.diacritic);
1597:             try expectEqual(.level, sp.tone);
1598:         }
1599: 
1600:         // Both vowel spans must end with horn; case and tone preserved.
1601:         const sp_first = state.buffer_effective[14];
1602:         try expectEqual(c.first_base, sp_first.base);
1603:         try expectEqual(.horn, sp_first.diacritic);
1604:         try expectEqual(.level, sp_first.tone);
1605: 
1606:         const sp_second = state.buffer_effective[15];
1607:         try expectEqual(c.second_base, sp_second.base);
1608:         try expectEqual(.horn, sp_second.diacritic);
1609:         try expectEqual(.level, sp_second.tone);
1610: 
1611:         // The trigger character at index 16 is out of buffer_effective range,
1612:         // so append_literal does not write a span there. We only assert the
1613:         // bookkeeping fields above.
